VALUES
  ('aboriginal-f7485f85-moex-00271', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於 X1 年初按面額$1,000 購入票面利率 5%每年底付息一次之債券，分類為透過其他綜合 損益按公允價值衡量金融資產。甲公司於X2年7月1日以$1,225（含應計利息）全數出售該債 券，對該公司 X2 年度本期其他綜合損益之影響數為損失$500，則該投資對該公司 X1 年本期其 他綜合損益之影響數為何？（不考慮所得稅及預期信用損失）', '["損失$100", "損失$500", "利益$100", "利益$500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00272', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '承上題，該金融資產投資對甲公司X2年本期淨利影響數為何？（不考慮所得稅及預期信用損失）', '["損失$100", "利益$25", "利益$225", "利益$525"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00273', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年中以$300,000購入乙公司30%普通股並分類為採用權益法之投資。乙公司X1年之 本期淨利$400,000，綜合損益總額$300,000（損失），並宣告發放現金股利$200,000。若甲公司對 乙公司投資之原始成本等於股權淨值，關於此投資，甲公司X1年底之帳面金額為：', '["$150,000", "$200,000", "$390,000", "$420,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00274', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X1年初發行面額$100,000，票面利率10%，有效利率12%，自X1年起每年6月30日 與12月31日付息之五年期公司債。關於該公司債，該公司X5年應認列之利息費用為：（四捨五 入至元）', '["$11,292", "$11,452", "$11,632", "$11,833"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00275', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於 X1 年底將一筆按重估價模式衡量之自用土地轉列為按公允價值模式衡量之投資性不動 產，該土地於X0年底之帳面金額為$1,000,000，公允價值為$800,000。若該土地原始取得成本為 $700,000，則此轉列交易對甲公司X0年之本期其他綜合損益之影響數為：（不考慮所得稅，四捨 五入至元）', '["$(200,000)", "$(100,000)", "$0", "$100,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00276', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年之綜合損益表中認列銷貨$51,000與預期信用損失$1,000。若甲公司X1年應收帳款 期初帳面金額$12,000（總帳面金額$15,000，備抵損失$3,000），期末帳面金額$10,000（總帳面金 額$12,000，備抵損失$2,000），且X1年沖銷應收帳款$2,000，則甲公司X1年對客戶之收現數為：', '["$52,000", "$53,000", "$54,000", "$55,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00277', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X0年初成立並發行面額$100，4%之累積且不參加特別股10,000股與普通股20,000股。 至 X3 年底，甲公司未再發行其他股份且 X0 年初所發行股份仍全數流通在外。若甲公司宣告發 放之X1年、X2年與X3年現金股利分別為$0、$20,000與$120,000，則甲公司之每股普通股可獲 分配之X3年現金股利為：', '["$0", "$1", "$2", "$4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00278', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年初發行2年期公司債，面額$1,500,000，票面利率為4%，有效利率為6%，每年6月 30日及12月31日付息。X2年1月1日公司以$1,400,000提前贖回公司債，試問此公司債之贖 回損益為何？（四捨五入至元）', '["損失$71,298", "利益$71,298", "損失$72,122", "利益$72,122"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00279', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年初以$500,000購入專利權，估計耐用年限5年，但未來經濟效益之消耗型態無法決 定，且該專利權無活絡市場亦無第三方承諾於耐用年限屆滿時購買。X3年初，該公司為該專利權 發生$60,000支出進行訴訟並獲勝訴，此勝訴使該專利權之預期未來經濟效益獲得維持。若甲公司 所有應攤銷無形資產之攤銷費用均應認列於本期淨利，該專利權對甲公司 X3 年之本期淨利影響 數為：（不考慮所得稅）', '["$(60,000)", "$(100,000)", "$(120,000)", "$(160,000)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00280', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司以舊設備並另支付現金$3,000 換入新設備，交換時舊設備之成本為$10,000，累計折舊為 $3,000，公允價值為$8,000。若此交換具商業實質，甲公司關於此交換應認列之利益為：', '["$0", "$1,000", "$2,000", "$3,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
